import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, Mail, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  Globe, CreditCard as CardIcon, Eye, Download, X, Upload, Trash2, Save,
  ShieldAlert, Landmark, Building, Menu, FileText, Calendar, Clock, HandCoins
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [showPaymentSystem, setShowPaymentSystem] = useState(false);

  // --- Central Data Engine ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'Pending', 
      amount: 12500, 
      dueDate: '2026-04-05', 
      phone: '+91 98765 43210', 
      email: 'rajesh.k@example.com', 
      joinDate: '12 Jan 2024',
      // Electricity Details
      prevReading: 1020,
      currReading: 1150,
      unitPrice: 8,
      // Late Fee Config
      lateFeePerDay: 50
    },
    { id: 2, name: 'Anita Sharma', room: 'B-204', status: 'Pending', amount: 15000, dueDate: '2026-04-05', phone: '+91 88776 65544', email: 'anita.s@example.com', joinDate: '05 Feb 2025', prevReading: 500, currReading: 580, unitPrice: 8, lateFeePerDay: 50 },
  ]);

  const [notifications, setNotifications] = useState([
    { id: 1, title: 'Server Maintenance', desc: 'Portal will be down at 2 AM IST.', time: '2h ago', type: 'info' },
  ]);

  // --- Logic Calculations ---
  const calculateElectricity = (t) => (t.currReading - t.prevReading) * t.unitPrice;

  const calculateLateFee = (t) => {
    const due = new Date(t.dueDate);
    const today = new Date();
    const diffTime = today - due;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays > 5 ? (diffDays - 5) * t.lateFeePerDay : 0;
  };

  const getTotalPayable = (t) => t.amount + calculateElectricity(t) + calculateLateFee(t);

  // --- Action Handlers ---
  const requestCashApproval = (tenantId) => {
    setTenants(prev => prev.map(t => 
      t.id === tenantId ? { ...t, status: 'Pending Approval' } : t
    ));
    setNotifications(prev => [{
      id: Date.now(),
      title: 'Approval Required',
      desc: `Tenant ${tenantId} marked Rent as Paid in Cash.`,
      time: 'Just now',
      type: 'alert'
    }, ...prev]);
    setShowPaymentSystem(false);
  };

  const handleLandlordAction = (tenantId, action) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        return { 
          ...t, 
          status: action === 'approve' ? 'Paid' : 'Pending',
          date: action === 'approve' ? new Date().toLocaleDateString() : 'N/A',
          method: action === 'approve' ? 'Cash' : 'N/A'
        };
      }
      return t;
    }));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-4 font-sans">
        <div className="w-full max-w-4xl bg-white rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic">H</div> Homely
            </div>
            <h1 className="text-5xl font-black leading-tight italic">Your Home,<br/>Managed.<br/>Better.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-xs italic">Manual Payment Enabled</p>
          </div>
          <div className="p-8 md:p-16 flex flex-col justify-center">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-10">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <form onSubmit={(e) => {e.preventDefault(); setUserRole(loginMode); setActiveTab(loginMode === 'admin' ? 'Dashboard' : 'Overview');}} className="space-y-4">
              <input type="text" placeholder="ID Number / Mobile" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <input type="password" placeholder="Password" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <button className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] text-xs shadow-2xl hover:bg-indigo-600 transition-all">Sign In</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} notifications={notifications} activeTab={activeTab} setActiveTab={setActiveTab} onAction={handleLandlordAction} logout={() => setUserRole(null)} />
  ) : (
    <TenantPortal 
      tenant={tenants[0]} 
      showPayment={showPaymentSystem} 
      setShowPayment={setShowPaymentSystem} 
      onPay={requestCashApproval} 
      calcElec={calculateElectricity}
      calcLate={calculateLateFee}
      calcTotal={getTotalPayable}
      logout={() => setUserRole(null)} 
    />
  );
};

const AdminPortal = ({ tenants, notifications, activeTab, setActiveTab, onAction, logout }) => {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 text-white p-8 flex flex-col transition-transform md:relative md:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex items-center justify-between mb-12">
          <div className="flex items-center gap-3 font-black italic text-xl">H Homely</div>
          <button onClick={() => setSidebarOpen(false)} className="md:hidden"><X/></button>
        </div>
        <nav className="space-y-2">
          {['Dashboard', 'Tenants', 'Payments'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeTab === tab ? 'bg-indigo-600' : 'text-slate-500'}`}>{tab}</button>
          ))}
          <button onClick={logout} className="w-full text-left px-6 py-4 text-red-500 text-[10px] font-black uppercase mt-10">Logout</button>
        </nav>
      </aside>

      <main className="flex-1 overflow-y-auto p-12">
        <header className="flex justify-between items-center mb-12">
          <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
        </header>

        {activeTab === 'Dashboard' && (
          <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
            <div className="p-10 border-b"><h3 className="text-xs font-black uppercase italic">Pending Approvals</h3></div>
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase border-b">
                <tr><th className="px-10 py-4">Tenant</th><th className="px-10 py-4">Status</th><th className="px-10 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody>
                {tenants.map(t => (
                  <tr key={t.id} className="border-b last:border-0">
                    <td className="px-10 py-6 font-bold text-xs">{t.name} ({t.room})</td>
                    <td className="px-10 py-6">
                      <span className={`px-4 py-1 rounded-full text-[8px] font-black uppercase ${t.status === 'Pending Approval' ? 'bg-amber-100 text-amber-600' : t.status === 'Paid' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100'}`}>
                        {t.status}
                      </span>
                    </td>
                    <td className="px-10 py-6 text-right">
                      {t.status === 'Pending Approval' && (
                        <div className="flex gap-2 justify-end">
                          <button onClick={() => onAction(t.id, 'approve')} className="bg-emerald-500 text-white px-4 py-2 rounded-lg text-[9px] font-black">APPROVE</button>
                          <button onClick={() => onAction(t.id, 'reject')} className="bg-red-500 text-white px-4 py-2 rounded-lg text-[9px] font-black">REJECT</button>
                        </div>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
};

const TenantPortal = ({ tenant, showPayment, setShowPayment, onPay, calcElec, calcLate, calcTotal, logout }) => {
  const [activeTab, setActiveTab] = useState('Overview');
  const electricity = calcElec(tenant);
  const lateFee = calcLate(tenant);
  const total = calcTotal(tenant);

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col font-sans">
      <header className="h-24 bg-white border-b px-12 flex items-center justify-between sticky top-0 z-50">
         <div className="flex items-center gap-3 italic font-black text-xl text-indigo-600">MyHome</div>
         <nav className="flex gap-10">
            {['Overview', 'History', 'Settings'].map(t => (
               <button key={t} onClick={() => setActiveTab(t)} className={`text-[10px] font-black uppercase tracking-widest pb-1 border-b-2 transition-all ${activeTab === t ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent'}`}>{t}</button>
            ))}
            <button onClick={logout} className="text-[10px] font-black uppercase text-red-500">Sign Out</button>
         </nav>
      </header>

      <main className="p-12 max-w-6xl mx-auto w-full flex-1">
        {activeTab === 'Overview' && (
           <div className="space-y-12 animate-in slide-in-from-bottom-8">
              <div className="bg-slate-900 rounded-[3.5rem] p-16 text-white shadow-2xl relative overflow-hidden">
                 <p className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest italic">Total Payable • {tenant.room}</p>
                 <h2 className="text-7xl font-black tracking-tighter italic mb-8">₹{total.toLocaleString()}</h2>
                 
                 <div className="grid grid-cols-2 md:grid-cols-3 gap-6 mb-12 border-t border-white/10 pt-8">
                    <div><p className="text-[9px] uppercase text-slate-500">Base Rent</p><p className="font-bold">₹{tenant.amount}</p></div>
                    <div><p className="text-[9px] uppercase text-slate-500">Electricity</p><p className="font-bold">₹{electricity}</p></div>
                    {lateFee > 0 && <div><p className="text-[9px] uppercase text-red-400">Late Fee</p><p className="font-bold text-red-400">₹{lateFee}</p></div>}
                 </div>

                 <div className="flex gap-4">
                    {tenant.status === 'Paid' ? (
                        <div className="flex items-center gap-3 bg-emerald-500/20 text-emerald-400 px-8 py-4 rounded-2xl font-black uppercase text-xs border border-emerald-500/30"><CheckCircle2 size={20}/> Payment Confirmed</div>
                    ) : tenant.status === 'Pending Approval' ? (
                        <div className="flex items-center gap-3 bg-amber-500/20 text-amber-400 px-8 py-4 rounded-2xl font-black uppercase text-xs border border-amber-500/30"><Clock size={20}/> Pending Approval</div>
                    ) : (
                        <button onClick={() => setShowPayment(true)} className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-black uppercase text-xs shadow-2xl hover:scale-105 transition-all">Pay Rent Now</button>
                    )}
                 </div>
              </div>
           </div>
        )}
      </main>

      {showPayment && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-2xl rounded-[4rem] overflow-hidden shadow-2xl animate-in zoom-in-95">
              <div className="p-16 flex flex-col items-center space-y-8">
                 <div className="text-center">
                    <HandCoins className="mx-auto text-indigo-600 mb-4" size={48}/>
                    <h4 className="text-3xl font-black italic uppercase">Cash Payment</h4>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Manual Approval Required</p>
                 </div>
                 
                 <div className="w-full bg-slate-50 p-8 rounded-3xl border border-slate-100">
                    <div className="flex justify-between items-center mb-2">
                       <span className="text-[10px] font-black uppercase text-slate-400">Total Due</span>
                       <span className="text-2xl font-black italic text-slate-900">₹{total.toLocaleString()}</span>
                    </div>
                    <p className="text-[9px] text-slate-400 leading-relaxed">
                       By clicking below, you confirm that you have handed over the cash amount to the landlord. A notification will be sent for manual verification.
                    </p>
                 </div>

                 <div className="flex flex-col w-full gap-4">
                    <button onClick={() => onPay(tenant.id)} className="w-full bg-slate-900 text-white py-6 rounded-3xl font-black uppercase text-[11px] tracking-[0.2em] shadow-xl hover:bg-indigo-600 transition-all">I Have Paid in Cash</button>
                    <button onClick={() => setShowPayment(false)} className="w-full text-slate-400 py-2 font-black uppercase text-[9px]">Cancel</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;
